import axios from 'axios'

const http = axios.create({
  baseURL: '/api',
  timeout: 30000
})

// 请求拦截器
http.interceptors.request.use(
  config => config,
  error => Promise.reject(error)
)

// 响应拦截器
http.interceptors.response.use(
  response => response.data,
  error => {
    const msg = error.response?.data?.detail || error.response?.data?.message || error.message || '网络请求失败'
    return Promise.reject(new Error(msg))
  }
)

/**
 * 获取统计数据
 * @param {Object} params 查询参数
 * @returns {Promise}
 */
export const getStats = (params = {}) => {
  return http.get('/stats', { params })
}

/**
 * 获取识别记录列表
 * @param {Object} params 查询参数
 * @returns {Promise}
 */
export const getDetectionRecords = (params = {}) => {
  return http.get('/detection-records', { params })
}

/**
 * 获取识别记录详情
 * @param {number} recordId 记录ID
 * @returns {Promise}
 */
export const getDetectionRecordDetail = (recordId) => {
  return http.get(`/detection-records/${recordId}`)
}
